8	// assertPressure is a test helper that checks utilization and pressure level.
9	func assertPressure(t *testing.T, m *SessionMetrics, wantPressure string, wantUtilApprox float64) {
10		t.Helper()
11		if m.PressureLevel != wantPressure {
12			t.Errorf("PressureLevel = %q, want %q (utilization=%.1f%%)", m.PressureLevel, wantPressure, m.ContextUtilization)
13		}
14		if math.Abs(m.ContextUtilization-wantUtilApprox) > 1.0 {
15			t.Errorf("ContextUtilization = %.1f%%, want ~%.1f%%", m.ContextUtilization, wantUtilApprox)
16		}
17	}
