1	// Package tailer provides transcript tailing and metrics computation.
2	// Format-specific parsing is delegated to TranscriptParser implementations
3	// that live in each agent adapter package.
4	package tailer
5	
6	import (
7		"regexp"
8		"strings"
9		"time"
10	)
11	
12	// ToolUse represents a single tool invocation with its unique ID.
13	type ToolUse struct {
14		ID   string // unique tool call ID (e.g. "toolu_01FUU...", "call_TkY0...", "call_63hf...")
15		Name string // tool name (e.g. "Bash", "Read", "shell")
16	}
17	
18	// ParsedEvent is the normalized output from a format-specific transcript parser.
19	// Each parser maps its native event structure into these fields.
20	type ParsedEvent struct {
21		EventType string    // normalized: "assistant_message", "user_message", "turn_done", etc.
22		Timestamp time.Time // event timestamp
23		Skip      bool      // true → ignore this line entirely
24	
25		// Tool tracking — parser reports deltas, tailer accumulates.
26		ToolUses      []ToolUse // tool invocations from this event (id + name)
27		ToolResultIDs []string  // IDs of completed tool results in this event
28		IsError       bool      // true if the tool result had is_error=true
29		ClearToolNames bool     // true → reset open tool state (on user messages)
30	
31		// IsUserInterrupt is true only for real user ESC cancellations — the
32		// exact "[Request interrupted by user]" text marker on a user event,
33		// without the "for tool use" suffix. Kept distinct from IsError so the
34		// classifier can tell an ESC apart from a normal tool failure (grep
35		// with no matches, a failing build, etc.). See issue #102 Bug B.
36		IsUserInterrupt bool
37	
38		// IsToolDenial is true when the user denied a permission prompt for a
39		// tool call ("[Request interrupted by user for tool use]" text marker).
40		// This is a *different* signal from IsUserInterrupt: a tool denial does
41		// not end the agent's turn — the agent typically continues with a
42		// different approach — so it must NOT feed the cancellation rule.
43		// Tracked separately for observability and to suppress the spurious
44		// working→ready→working flicker that happened when the parser lumped
45		// both markers under IsUserInterrupt.
46		IsToolDenial bool
47	
48		// Metadata extracted by the parser.
49		ModelName        string
50		ContextWindow    int64
51		Tokens           *TokenSnapshot // nil = no token data in this event
52		CumulativeTokens *TokenSnapshot // cumulative totals (set by Codex); tailer uses directly for cost
53		RequestID        string         // unique API call ID — deduplicates streaming events for cost accumulation
54		AssistantText    string         // ≤200 chars, for waiting-state display
55		ContentChars     int64          // character count for token estimation
56		CWD              string         // working directory if found
57		PermissionMode   string         // Claude Code only
58	}
59	
60	// TokenSnapshot holds a token breakdown from a single event.
61	type TokenSnapshot struct {
62		Input         int64
63		Output        int64
64		CacheRead     int64
65		CacheCreation int64
66		Total         int64
67	}
68	
69	// TranscriptParser parses a single JSONL line from a specific transcript format
70	// and returns a normalized ParsedEvent. Implementations live in each agent
71	// adapter package (claudecode, codex, pi).
72	type TranscriptParser interface {
73		// ParseLine parses a raw JSON map and returns a normalized event.
74		// Returns nil for lines that should be silently ignored (no event emitted).
75		ParseLine(raw map[string]interface{}) *ParsedEvent
76	}
77	
78	// --- Shared helpers used by multiple parsers ---
79	
80	// IsUserEventType reports whether a ParsedEvent.EventType represents a user
81	// turn across any of the supported transcript formats.
82	func IsUserEventType(eventType string) bool {
83		switch eventType {
84		case "user", "user_message", "user_input":
85			return true
86		}
87		return false
88	}
