90	// NormalizeModelName normalizes model names by removing date suffixes, extended
91	// context markers, and handling aliases. Exported for use by adapter parsers.
92	func NormalizeModelName(rawModel string) string {
93		if rawModel == "" {
94			return ""
95		}
96	
97		// Strip extended context suffix (e.g. "claude-opus-4-6[1m]")
98		rawModel = strings.TrimSuffix(rawModel, "[1m]")
99	
100		// Handle common aliases first
101		aliases := map[string]string{
102			"opusplan": "claude-opus-4-1",
103			"sonnet":   "claude-sonnet-4-6",
104			"haiku":    "claude-haiku-4-5",
105		}
106		if normalized, exists := aliases[rawModel]; exists {
107			return normalized
108		}
109	
110		// Remove date suffixes (e.g., "claude-opus-4-6-20250715" -> "claude-opus-4-6")
111		datePattern := regexp.MustCompile(`-\d{8}$`)
112		normalized := datePattern.ReplaceAllString(rawModel, "")
113	
114		// Match most-specific patterns first (longer model IDs before shorter)
115		switch {
116		case strings.Contains(normalized, "claude-opus-4-6"):
117			return "claude-opus-4-6"
118		case strings.Contains(normalized, "claude-sonnet-4-6"):
119			return "claude-sonnet-4-6"
120		case strings.Contains(normalized, "claude-sonnet-4-5"):
121			return "claude-sonnet-4-5"
122		case strings.Contains(normalized, "claude-haiku-4-5"):
123			return "claude-haiku-4-5"
124		case strings.Contains(normalized, "claude-opus-4-1"):
125			return "claude-opus-4-1"
126		case strings.Contains(normalized, "claude-sonnet-4"):
127			return "claude-4-sonnet"
128		case strings.Contains(normalized, "claude-3.5-sonnet"):
129			return "claude-3.5-sonnet"
130		case strings.Contains(normalized, "claude-3.5-haiku"):
131			return "claude-3.5-haiku"
132		}
133		return normalized
134	}
