136	// ExtractAssistantText extracts and concatenates text blocks from an assistant
137	// message, returning at most 200 characters. Checks both Claude Code
138	// (message.content[].text) and Codex (content[].text / content[].output_text) formats.
139	func ExtractAssistantText(raw map[string]interface{}) string {
140		var parts []string
141	
142		collectText := func(arr []interface{}) {
143			for _, item := range arr {
144				if block, ok := item.(map[string]interface{}); ok {
145					bt := block["type"]
146					if bt == "text" || bt == "output_text" {
147						if text, ok := block["text"].(string); ok && text != "" {
148							parts = append(parts, text)
149						}
150					}
151				}
152			}
153		}
154	
155		// Claude Code: message.content[]
156		if msg, ok := raw["message"].(map[string]interface{}); ok {
157			if arr, ok := msg["content"].([]interface{}); ok {
158				collectText(arr)
159			}
160		}
161		// Codex: top-level content[]
162		if arr, ok := raw["content"].([]interface{}); ok {
163			collectText(arr)
164		}
165	
166		var text string
167		switch len(parts) {
168		case 0:
169			return ""
170		case 1:
171			text = strings.TrimSpace(parts[0])
172		default:
173			text = strings.TrimSpace(strings.Join(parts, " "))
174		}
175	
176		runes := []rune(text)
177		if len(runes) > 200 {
178			return string(runes[:200])
179		}
180		return text
181	}
182	
183	// ExtractContentChars returns the total character count of text content in
184	// a transcript event, checking common content locations across formats.
185	func ExtractContentChars(raw map[string]interface{}) int64 {
186		var chars int64
187		addContentChars := func(arr []interface{}) {
188			for _, item := range arr {
189				if block, ok := item.(map[string]interface{}); ok {
190					if text, ok := block["text"].(string); ok {
191						chars += int64(len(text))
192					}
193				}
194			}
195		}
196		// Top-level content array (Codex newer format)
197		if arr, ok := raw["content"].([]interface{}); ok {
198			addContentChars(arr)
199		}
200		// Nested message.content array (Claude Code format)
201		if msg, ok := raw["message"].(map[string]interface{}); ok {
202			if arr, ok := msg["content"].([]interface{}); ok {
203				addContentChars(arr)
204			}
205		}
206		// Codex function_call arguments
207		if args, ok := raw["arguments"].(string); ok {
208			chars += int64(len(args))
209		}
210		// Codex function_call_output
211		if output, ok := raw["output"].(string); ok {
212			chars += int64(len(output))
213		}
214		return chars
215	}
216	
217	// ExtractUsage pulls token breakdown fields from a usage map.
218	// Handles both standard (Claude/Codex) and Pi field naming conventions.
219	func ExtractUsage(usage map[string]interface{}) *TokenSnapshot {
220		snap := &TokenSnapshot{}
221		hasBreakdown := false
222	
223		if v, ok := usage["input_tokens"].(float64); ok {
224			snap.Input = int64(v)
225			hasBreakdown = true
226		}
227		if v, ok := usage["output_tokens"].(float64); ok {
228			snap.Output = int64(v)
229			hasBreakdown = true
230		}
231		// Pi uses shorter field names as fallback.
232		if !hasBreakdown {
233			if v, ok := usage["input"].(float64); ok {
234				snap.Input = int64(v)
235				hasBreakdown = true
236			}
237			if v, ok := usage["output"].(float64); ok {
238				snap.Output = int64(v)
239				hasBreakdown = true
240			}
241		}
242		// Standard cache field names.
243		if v, ok := usage["cache_read_input_tokens"].(float64); ok {
244			snap.CacheRead = int64(v)
245		}
246		if v, ok := usage["cache_creation_input_tokens"].(float64); ok {
247			snap.CacheCreation = int64(v)
248		}
249		// Pi cache field names.
250		if v, ok := usage["cacheRead"].(float64); ok {
251			snap.CacheRead = int64(v)
252		}
253		if v, ok := usage["cacheWrite"].(float64); ok {
254			snap.CacheCreation = int64(v)
255		}
256		snap.Total = snap.Input + snap.Output + snap.CacheRead + snap.CacheCreation
257		// total_tokens override
258		if total, ok := usage["total_tokens"].(float64); ok {
259			snap.Total = int64(total)
260		}
261		// Pi totalTokens field.
262		if total, ok := usage["totalTokens"].(float64); ok {
263			snap.Total = int64(total)
264		}
265	
266		if !hasBreakdown && snap.Total == 0 {
267			return nil
268		}
269		return snap
270	}
271	
272	// ParseTimestamp extracts a timestamp from a raw JSON map, trying RFC3339
273	// and millisecond-precision formats, then numeric Unix timestamps.
274	func ParseTimestamp(raw map[string]interface{}) time.Time {
275		if ts, ok := raw["timestamp"]; ok {
276			if tsStr, ok := ts.(string); ok {
277				if parsed, err := time.Parse(time.RFC3339, tsStr); err == nil {
278					return parsed
279				}
280				if parsed, err := time.Parse("2006-01-02T15:04:05.000Z", tsStr); err == nil {
281					return parsed
282				}
283			} else if tsNum, ok := ts.(float64); ok && tsNum > 0 {
284				return time.Unix(int64(tsNum), 0)
285			}
286		}
287		return time.Now()
288	}
