10	func TestCost_SingleRequestID_MultipleStreams(t *testing.T) {
11		path := writeTranscriptLines(t, []map[string]interface{}{
12			{"type": "user", "timestamp": ts(0)},
13			// First streaming event — partial usage.
14			{
15				"type": "assistant", "timestamp": ts(1), "requestId": "req-1",
16				"message": map[string]interface{}{
17					"model": "claude-sonnet-4-20250514",
18					"usage": map[string]interface{}{
19						"input_tokens": float64(1000), "output_tokens": float64(50),
20						"cache_read_input_tokens": float64(500), "cache_creation_input_tokens": float64(200),
21					},
22				},
23			},
