331				"type": "assistant", "timestamp": ts(3), "requestId": "req-2",
332				"message": map[string]interface{}{
333					"model": "claude-sonnet-4-20250514",
334					"usage": map[string]interface{}{
335						"input_tokens": float64(20000), "output_tokens": float64(8000),
336					},
337				},
338			},
339		})
340	
341		tailer := newTestTailer(path)
342		m, err := tailer.TailAndProcess()
343		if err != nil {
344			t.Fatal(err)
345		}
346	
347		// The cost should be based on cumulative (30000 input + 13000 output),
348		// not the snapshot (20000 input + 8000 output).
349		if m.EstimatedCostUSD == 0 {
350			t.Skip("no pricing data for claude-sonnet-4-20250514; cost validation skipped")
351		}
352	
353		// Verify the cost is greater than what the snapshot alone would give.
354		// snapshot cost = EstimateCostUSD(20000, 8000, 0, 0)
355		// cumulative cost = EstimateCostUSD(30000, 13000, 0, 0)
356		// The cumulative cost should be higher because it includes both turns.
357		snapshotCost := tailer.capacityMgr.EstimateCostUSD(
358			"claude-sonnet-4-20250514", 20000, 8000, 0, 0)
359		cumulativeCost := tailer.capacityMgr.EstimateCostUSD(
360			"claude-sonnet-4-20250514", 30000, 13000, 0, 0)
361	
362		if snapshotCost == 0 {
363			t.Skip("no pricing data for claude-sonnet-4-20250514")
364		}
