366		if math.Abs(m.EstimatedCostUSD-cumulativeCost) > 0.0001 {
367			t.Errorf("EstimatedCostUSD = %.6f, want %.6f (cumulative); snapshot would be %.6f",
368				m.EstimatedCostUSD, cumulativeCost, snapshotCost)
369		}
370	}
